```python
class Flight:
    def __init__(self, flightNo, destination):
        self.__flightNo = flightNo
        self.__destination = destination

    @property
    def flightNo(self):
        return self.__flightNo

    @property
    def destination(self):
        return self.__destination

    def __str__(self):
        return f'Flight: {self.__flightNo} to {self.__destination}'


class Passenger:
    def __init__(self, ppNo, name, flight):
        self.__ppNo = ppNo
        self.__name = name
        self.__flight = flight

    @property
    def flight(self):
        return self.__flight

    @flight.setter
    def flight(self, newFlight):
        self.__flight = newFlight

    def __str__(self):
        return f'{self.__name} | {self.__flight}'
```

Usage:
```python
f1 = Flight('SQ1', 'London')
p1 = Passenger('PP1', 'John', f1)
print(p1)  # John | Flight: SQ1 to London
```

Notice that when we print the Passenger, it calls the Flight's `__str__` automatically.

A PhoneBook manages a list of Contact objects with add, search, and remove:

```python
class Contact:
    def __init__(self, name, number):
        self.__name = name
        self.__number = number

    @property
    def name(self):
        return self.__name

    def __str__(self):
        return f'{self.__name}: {self.__number}'


class PhoneBook:
    def __init__(self):
        self.__contacts = []

    def addContact(self, contact):
        self.__contacts.append(contact)

    def searchContact(self, name):
        for c in self.__contacts:
            if c.name.lower() == name.lower():
                return c
        return None

    def removeContact(self, name):
        c = self.searchContact(name)
        if c:
            self.__contacts.remove(c)
            return True
        return False
```

This pattern of add/search/remove comes up very often in ICT162 exams.
